import React, { useContext, useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { AuthContext } from '../../context/AuthContext';

const AdminDashboard = () => {
  const { user, logout } = useContext(AuthContext);
  const [stats, setStats] = useState({ products: 0, orders: 0 });
  const [recentOrders, setRecentOrders] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchStats();
    fetchRecentOrders();
  }, []);

  const fetchStats = async () => {
    try {
      const token = JSON.parse(localStorage.getItem('userInfo'))?.token;
      const productsRes = await fetch('http://localhost:5000/api/products', {
        headers: { Authorization: `Bearer ${token}` },
      });
      const productsData = await productsRes.json();

      setStats({
        products: productsData.count || productsData.products?.length || 0,
        orders: 0,
      });
    } catch {
      setStats({ products: 8, orders: 0 });
    }
  };

  const fetchRecentOrders = async () => {
    setRecentOrders([]);
    setLoading(false);
  };

  return (
    <div className="min-h-screen bg-[#f9f5f1] text-[#2c2c2c] font-sans transition">
      <div className="max-w-6xl mx-auto px-6 py-8">
        {/* Tiêu đề */}
        <div className="mb-8 flex justify-between items-center">
          <h2 className="text-2xl font-semibold text-[#2c2c2c]">🌸 Tổng quan</h2>
          <div className="text-sm text-[#8b5e3c]">
            Xin chào, <span className="font-medium">{user?.name || 'Admin'}</span>
          </div>
        </div>

        {/* Thống kê nhanh */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-10">
          <div className="bg-white border border-[#e4c6ba] rounded-xl shadow-sm p-6 hover:shadow-md transition">
            <h3 className="text-lg font-semibold text-[#2c2c2c] mb-2 flex items-center gap-2">
              🌷 Sản phẩm
            </h3>
            <p className="text-4xl font-bold text-[#e06c7f]">{stats.products}</p>
            <Link
              to="/admin/products"
              className="text-[#8b5e3c] hover:text-[#e06c7f] text-sm mt-3 inline-block transition"
            >
              Xem chi tiết →
            </Link>
          </div>

          <div className="bg-white border border-[#e4c6ba] rounded-xl shadow-sm p-6 hover:shadow-md transition">
            <h3 className="text-lg font-semibold text-[#2c2c2c] mb-2 flex items-center gap-2">
              💌 Đơn hàng
            </h3>
            <p className="text-4xl font-bold text-[#e06c7f]">{stats.orders}</p>
            <Link
              to="/admin/orders"
              className="text-[#8b5e3c] hover:text-[#e06c7f] text-sm mt-3 inline-block transition"
            >
              Xem chi tiết →
            </Link>
          </div>
        </div>

        {/* Đơn hàng gần đây */}
        <div className="bg-white border border-[#e4c6ba] rounded-xl shadow-sm overflow-hidden">
          <div className="flex justify-between items-center px-6 py-4 border-b border-[#e4c6ba]">
            <h3 className="text-lg font-semibold text-[#2c2c2c]">
              🕊️ Đơn hàng gần đây
            </h3>
          </div>

          {loading ? (
            <div className="p-6 text-center text-[#8b5e3c]">Đang tải...</div>
          ) : recentOrders.length === 0 ? (
            <div className="p-6 text-center text-[#8b5e3c99]">
              Chưa có đơn hàng nào 🌸
            </div>
          ) : (
            <table className="min-w-full text-sm text-[#2c2c2c]">
              <thead className="bg-[#f9f5f1] border-b border-[#e4c6ba]">
                <tr>
                  <th className="px-6 py-3 text-left font-semibold">Mã đơn</th>
                  <th className="px-6 py-3 text-left font-semibold">Khách hàng</th>
                  <th className="px-6 py-3 text-left font-semibold">Ngày đặt</th>
                  <th className="px-6 py-3 text-left font-semibold">Tổng tiền</th>
                  <th className="px-6 py-3 text-left font-semibold">Trạng thái</th>
                </tr>
              </thead>
              <tbody>
                {recentOrders.map((order) => (
                  <tr
                    key={order._id}
                    className="hover:bg-[#f9f5f1] transition-colors"
                  >
                    <td className="px-6 py-4">{order._id}</td>
                    <td className="px-6 py-4">{order.user?.name}</td>
                    <td className="px-6 py-4">
                      {new Date(order.createdAt).toLocaleDateString('vi-VN')}
                    </td>
                    <td className="px-6 py-4">
                      {order.totalPrice.toLocaleString('vi-VN')}₫
                    </td>
                    <td className="px-6 py-4">
                      <span className="px-3 py-1 text-xs font-semibold rounded-full bg-[#e06c7f22] text-[#2c2c2c]">
                        {order.status}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
